def sort_numbers(numbers: str) -> str:
    number_map = {'zero': 0, 'one': 1, 'two': 2, 'three': 3, 
                  'four': 4, 'five': 5, 'six': 6, 'seven': 7, 
                  'eight': 8, 'nine': 9}

    sorted_numbers = []
    for num in numbers.split():
        if num in number_map:
            sorted_numbers.append((num, number_map[num]))
        else:
            raise ValueError(f"Invalid input: {num}")

    sorted_numbers.sort(key=lambda x: x[1])
    return ' '.join([num[0] for num in sorted_numbers])

