function common(array $l1, array $l2) {
    // Create an empty array to store unique common elements
    $commonElements = [];

    // Loop through each element in the first list
    foreach ($l1 as $element) {
        // Check if the element exists in the second list and it's not already present in the common elements
        if (in_array($element, $l2) && !in_array($element, $commonElements)) {
            // Add the element to the common elements array
            $commonElements[] = $element;
        }
    }

    // Sort the common elements array
    sort($commonElements);

    return $commonElements;
}

