public static List<Integer> sumProduct(List<Object> numbers) {
    int sum = 0;
    int product = 1;

    for (Object num : numbers) {
        if (!(num instanceof Integer)) {
            throw new IllegalArgumentException("The list should only contain integers.");
        }
        int val = (int) num;
        sum += val;
        product *= val;
    }

    return Arrays.asList(sum, product);
}

function largestPrimeFactor($n) {
    $max_prime = 1; // Initialize max prime factor to 1 (since we know n is not a prime)

    for ($i = 2; $i * $i <= $n; $i++) { // Start from 2, as smallest prime number
        while ($n % $i == 0) { // If i is a factor of n
            $max_prime = $i;
            $n /= $i; // Divide n by i to find next potential factor
        }
    }

    if ($n > 1) { // If n itself is prime (since it's not divisible by any other number)
        $max_prime = $n;
    }

    return $max_prime;
}

def largest_prime_factor(n: int):
    i = 2
    while i * i <= n:
        if n % i:
            i += 1
        else:
            n //= i
            i = 2
    return n

sub triangle_area {
    my ($a, $b, $c) = @_;

    # Check if the three sides form a valid triangle
    return -1 unless $a + $b > $c and $a + $c > $b and $b + $c > $a;

    # Calculate the semi-perimeter of the triangle
    my $s = ($a + $b + $c) / 2;

    # Calculate the area using Heron's formula
    my $area = sqrt($s * ($s - $a) * ($s - $b) * ($s - $c));

    return sprintf("%.2f", $area);
}

