    my @result;
    my %rows;

    # First, find all the rows that contain $x
    for my $i (0 .. @$lst-1) {
        my $row = $lst->[$i];
        if (grep { $_ == $x } @$row) {
            foreach my $j (0 .. @{$row}-1) {
                push @{$rows{$i}}, [$i, $j];
            }
        }
    }

    # Then, sort the coordinates by row and column
    for my $i (keys %rows) {
