        @result = (@result, @temp);
    }

    return @result;
}

function isMultiplyPrime($a) {
    $primeNumbers = array();
    for ($i = 2; $i <= sqrt($a); $i++) {
        if (isPrime($i)) {
            $divisors = getDivisors($i);
            foreach ($divisors as $divisor) {
                if ($divisor > 1 && isPrime($divisor) && $a % $divisor === 0) {
                    $primeNumbers[] = $i;
                    break;
                }
            }
        }
    }
    return count($primeNumbers) >= 3;
}

