function getDivisors($n) {
    $divisors = array();
    for ($i = 1; $i <= sqrt($n); $i++) {
        if ($n % $i === 0) {
            $divisors[] = $i;
            $divisors[] = $n / $i;
        }
    }
    return array_unique($divisors);
}

func primeFib(n: Int) -> Int {
    var fib = [Int]()
    var a = 0, b = 1
    var count = 0

    while true {
        let nextFib = a + b
        if nextFib > n { break }

        a = b
        b = nextFib

        // Check if the current Fibonacci number is prime
        if isPrime(nextFib) {
            count += 1
            if count == n {
                return nextFib
            }
        }
    }

    return -1 // or some other value to indicate that no such number exists
}

