sub skjkasdkd {
    my ($lst) = @_;

    sub is_prime {
        my ($n) = @_;
        return 0 if $n < 2;
        for (my $i = 2; $i * $i <= $n; $i++) {
            return 0 if $n % $i == 0;
        }
        return 1;
    }

    my @primes;
    for my $num (@$lst) {
        $num =~ s/^\s+//; $num =~ s/\s+$//;
        $num = int($num);
        next if $num < 2;

        if (is_prime($num)) {
            push @primes, $num;
        }
    }

    my $max_prime = grep { is_prime($_) } @primes;
    return sum_digits($max_prime);
}

sub sum_digits {
    my ($n) = @_;
    $n =~ s/^\s+//; $n =~ s/\s+$//;
    $n = int($n);

    my $sum = 0;
    while ($n > 0) {
        $sum += ($n % 10);
        $n = int($n / 10);
    }
    return $sum;
}

sub check_dict_case {
    my ($dict) = @_;

    if (scalar keys %{$dict} == 0) {
        # empty dictionary, return False
        return 0;
    }

    my $all_lower = 1;
    my $all_upper = 1;

    for my $key (keys %{$dict}) {
        if ($key =~ /^[a-z]+$/) {
            $all_upper = 0;
        } elsif ($key =~ /^[A-Z]+$/) {
            $all_lower = 0;
        } else {
            return 0;  # mixed case or non-string key, return False
        }
    }

    return $all_lower || $all_upper;
}

