object Main extends App {
    /**
     * For a given list of integers, return a tuple consisting of a sum and a product of all the integers in a list.
     * Empty sum should be equal to 0 and empty product should be equal to 1.
     */
    def sumProduct(numbers : List[Any]) : (Int, Int) = {
        val intNumbers = numbers.flatMap(a => a match {
            case i: Int => Some(i)
            case _ => None
        })

        val sum = intNumbers.foldLeft(0)(_ + _)
        val product = intNumbers.foldLeft(1)(_ * _)

        (sum, product)
    }

    def main(args: Array[String]) {
        println(sumProduct(Nil)) // prints: (0, 1)
        println(sumProduct(List(1, 2, 3, 4))) // prints: (10, 24)
    }
}

sub closest_integer {
    my ($value) = @_;

    # Convert the string value to a number (assuming it's a valid float)
    my $num = eval "$value";

    # Calculate the distance from the given number to each integer nearby
    my $diff_pos = abs($num - int($num));
    my $diff_neg = abs($num + 1 - int($num));

    # Return the integer that is farthest from zero (or equidistant if both are the same)
    return ($diff_pos >= $diff_neg) ? int($num + 1) : int($num);
}

