sub make_a_pile {
    my ($n) = @_;
    my @pile;

    while ($n > 0) {
        push @pile, $n;
        if ($n % 2 == 0) { # n is even
            $n = int($n / 2);
        } else { # n is odd
            $n = int(($n - 1) / 2) * 2 + 1;
        }
    }

    return @pile;
}

