function primeLength($string) {
    $length = strlen($string);
    if ($length < 2) return false; // prime numbers are greater than 1

    for ($i = 2; $i <= sqrt($length); $i++) { // only need to check up to sqrt(length)
        if ($length % $i === 0) {
            return false; // not a prime number
        }
    }

    return true; // length is a prime number
}

