    for ($i = 0; $i < count($lst); $i++) {
        foreach ($lst[$i] as $j => $value) {
            if ($value == $x) {
                $result[] = array($i, $j);
            }
        }
    }
    usort($result, function($a, $b) {
        if ($a[0] == $b[0]) {
            return $b[1] - $a[1];
        } else {
            return $a[0] - $b[0];
        }
    });
