function nextSmallest(array $lst): ?int {
    // Sort the array to ensure we can find the 2nd smallest element
    $sorted = sort($lst);

    // If the array is empty, return null (no 2nd smallest)
    if (empty($sorted)) {
        return null;
    }

    // Get the first and second elements of the sorted array
    $first = reset($sorted);
    $second = next($sorted);

    // If there's only one element left in the array, it means we have duplicates,
    // so return null (no 2nd smallest)
    if ($first === $second) {
        return null;
    }

    // Return the 2nd smallest element
    return $second;
}

