function checkDictCase($dict) {
    if (empty($dict)) {
        return false; // empty dictionary, return False
    }

    $allLower = true;
    $allUpper = true;

    foreach ($dict as $key => $value) {
        $keyIsLower = is_string($key) && strtolower($key) === $key;
        $keyIsUpper = is_string($key) && strtoupper($key) === $key;

        if (!$keyIsLower && !$keyIsUpper) {
            return false; // mixed case, return False
        }

        if (!($keyIsLower || $keyIsUpper)) {
            $allLower = false;
            $allUpper = false;
        }
    }

    return $allLower || $allUpper; // all keys in lower or upper case, return True
}

func median(l : [Int]) -> Double {
