sub max_fill {
    my ($grid, $capacity) = @_;

    my $total_wells = @{$grid};
    my $total_buckets = scalar @$grid[0];
    my $empty_buckets = 0;

    while (my $i = 0; $i < $total_wells; $i++) {
        my $water_in_well = 0;
        for my $j (0 .. $total_buckets - 1) {
            if ($grid->[$i]->[$j] == 1) {
                $water_in_well++;
            }
        }

        while (my $k = 0; $k < $capacity && $water_in_well > 0; $k++) {
            for my $j (0 .. $total_buckets - 1) {
                if ($grid->[$i]->[$j] == 1) {
                    $grid->[$i]->[$j] = 0;
                    $water_in_well--;
                }
            }
        }

        if ($water_in_well == 0) {
            $empty_buckets++;
        }
    }

    return $empty_buckets;
}

