public static String sortNumbers(String numbers) {
    // Split the input string into an array of strings, each representing a number
    String[] numArray = numbers.split(" ");

    // Create a HashMap to map number names to their integer values for easy comparison
    Map<String, Integer> numMap = new HashMap<>();
    numMap.put("zero", 0);
    numMap.put("one", 1);
    numMap.put("two", 2);
    numMap.put("three", 3);
    numMap.put("four", 4);
    numMap.put("five", 5);
    numMap.put("six", 6);
    numMap.put("seven", 7);
    numMap.put("eight", 8);
    numMap.put("nine", 9);

    // Sort the array of strings based on their integer values
    Arrays.sort(numArray, (a, b) -> {
        return numMap.get(a).compareTo(numMap.get(b));
    });

    // Join the sorted array into a single string with spaces in between
    String sortedNumbers = String.join(" ", numArray);

    return sortedNumbers;
}

