func rescale_to_unit(numbers []float64) []float64 {
	min := float64(1e9)
	max := -min
	for _, num := range numbers {
		if num < min {
			min = num
		}
		if num > max {
			max = num
		}
	}

	result := make([]float64, len(numbers))
	scale := 1.0 / (max - min)

	for i, num := range numbers {
		result[i] = (num - min) * scale
	}

	return result
}

