func search(lst: [Int]) -> Int {
    var maxFrequency = 0
    var result = -1

    for num in lst {
        if num > 0 {
            let frequency = countOccurrences(of: num, in: lst)
            if frequency >= num && frequency > maxFrequency {
                maxFrequency = frequency
                result = num
            }
        }
    }

    return result
}

