public static List<Double> rescaleToUnit(List<Double> numbers) {
    // Find the minimum and maximum values in the list
    double min = Collections.min(numbers);
    double max = Collections.max(numbers);

    // Create a new list to store the rescaled values
    List<Double> rescaledNumbers = new ArrayList<>();

    // Iterate over each number in the original list
    for (double num : numbers) {
        // Apply the linear transform: (num - min) / (max - min)
        double scaledNum = (num - min) / (max - min);

        // Add the rescaled value to the new list
        rescaledNumbers.add(scaledNum);
    }

    return rescaledNumbers;
}

