func triples_sum_to_zero(l []int) bool {
    // Sort the input slice to make it easier to find three elements that sum to zero
    sort.Slice(l, func(i, j int) bool { return l[i] < l[j] })

    for i := 0; i < len(l)-2; i++ {
        // Initialize two pointers, one at the next element and one at the end of the slice
        j, k := i + 1, len(l) - 1

        for ; j < k; j, k = j+1, k-1 {
            // Calculate the sum of the three elements
            s := l[i] + l[j] + l[k]

            // If the sum is zero, we found three distinct elements that sum to zero!
            if s == 0 {
                return true
            }
        }
    }

    // If we reach this point, no three elements sum to zero
    return false
}

func solve(n: Int) -> String {
    var n = n // create a copy of the input number
    var sum = 0 // initialize the sum

    // convert the number to binary and sum up its digits
    while n > 0 {
        let remainder = n % 2
        sum += remainder
        n /= 2
    }

    // convert the sum back to a binary string
    var result = ""
    var remainingSum = sum

    // loop until the sum is 0
    while remainingSum > 0 {
        // if the sum is odd, add '1' to the result and subtract 1 from the sum
        if remainingSum % 2 == 1 {
            result += "1"
            remainingSum -= 1
        } else {
            result += "0" // if the sum is even, just add '0'
        }
        remainingSum /= 2
    }

    return result.reversed().description
}

