var memo map[int]int

func init() {
	memo = make(map[int]int)
}

func fib4(n int) int {
	if val, ok := memo[n]; ok {
		return val
	}
	switch n % 4 {
	case 0:
		return A + fib4((n-1)%4)*D
	case 1:
		return B
	case 2:
		return C
	case 3:
		return A + (B-C) + fib4((n-1)%4)*C
	default:
		return -1 // invalid input
	}
}

