    }

    let keys = Array(dict.keys)
    var allLower = true
    var allUpper = true

    for key in keys {
        if let stringKey = key as? String {
            if !stringKey.lowercased().elementsEqual(stringKey) {
                allLower = false
            }
            if !stringKey.uppercased().elementsEqual(stringKey) {
