    if (n <= 1) return false
    if (n == 2) return true
    if (n % 2 == 0) return false

    val boundary = Math.sqrt(n.toDouble()).toInt()
    for (i in 3..boundary step 2) {
        if (n % i == 0) return false
    }
    return true
}

