    var bucketsFilled = 0

    for row in grid {
        let waterInRow = row.reduce(0, +)
        if waterInRow > 0 {
            let waterToTransfer = min(waterInRow, capacity)
            totalWater += waterToTransfer
            bucketsFilled += 1
        }
    }

