}

func is_happy(s string) bool {
    if len(s) < 3 {
        return false // too short, not happy
    }
    for i := 0; i <= len(s)-3; i++ { // check every 3-consecutive-letter chunk
        chunk := s[i : i+3]
        unique := true
        seen := make(map[rune]bool) // a rune is a single character (e.g., letter or digit)
        for j := 0; j < len(chunk); j++ {
            if _, ok := seen[chunk[j]]; ok {
                unique = false
                break
            }
            seen[chunk[j]] = true
        }
        if !unique {
            return false // not happy, found duplicate in chunk
        }
    }
    return true // happy!
}

