class TriplesSumToZero {
    public static Boolean triplesSumToZero(List<Integer> l) {
        Set<Integer> set = new HashSet<>(l);

        for (int i : set) {
            Set<Integer> remainingSet = new HashSet<>(set);
            remainingSet.remove(i);

            for (int j : remainingSet) {
                Set<Integer> finalSet = new HashSet<>(remainingSet);
                finalSet.remove(j);

                for (int k : finalSet) {
                    if (i + j + k == 0) {
                        return true;
                    }
                }
            }
        }

        return false;
    }
}

