func intersection(interval1: [Int], interval2: [Int]) -> String {
    let (start1, end1) = (interval1[0], interval1[1])
    let (start2, end2) = (interval2[0], interval2[1])

    var intersectionStart = max(start1, start2)
    var intersectionEnd = min(end1, end2)

    if intersectionStart > intersectionEnd {
        return "NO"
    }

    let intersectionLength = intersectionEnd - intersectionStart + 1

    func isPrime(_ number: Int) -> Bool {
        if number <= 1 { return false }
        for i in 2...Int(sqrt(Double(number))) {
            if number % i == 0 { return false }
        }
        return true
    }

    return isPrime(intersectionLength) ? "YES" : "NO"
}

