func tribonacci(_ n: Int) -> [Double] {
    if n == 0 {
        return []
    }

    var sequence = [Double]()
    if n >= 3 {
        sequence.append(Double(3))

        for _ in 2..<3 {
            let prev = sequence.last!
            sequence.append(1 + prev / 2)
        }

        for _ in 0...n-3 {
            let prev = sequence[sequence.count - 1]
            let prevToPrev = sequence[sequence.count - 2]
            sequence.append(prev + prevToPrev + (sequence.count > 2 ? sequence[sequence.count - 3] : Double(3)))
        }
    } else if n == 2 {
        sequence = [Double](repeating: 1, count: n+1)
        sequence[0] = Double(3)
        sequence[1] = 1 + (Double(2) / 2)
    } else {
        sequence = [Double](repeating: 3, count: n+1)
    }

    return sequence
}

