    var positiveIntegers = [AnyHashable]()

    for element in lst {
        if let integer = element as? Int, integer < 0 {
            negativeIntegers.append(element)
        } else if let integer = element as? Int, integer > 0 {
            positiveIntegers.append(element)
        }
    }

    var largestNegative: AnyHashable?
    var smallestPositive: AnyHashable?

