func orderByPoints(nums: [AnyHashable]) -> [AnyHashable] {
    return nums.sorted { (lhs, rhs) -> Bool in
        let lhsSum = lhs.hashValue.magnitude.digitify().reduce(0, +)
        let rhsSum = rhs.hashValue.magnitude.digitify().reduce(0, +)

        if lhsSum == rhsSum {
            return (nums.firstIndex(of: lhs as! Hashable) ?? 0) < (nums.firstIndex(of: rhs as! Hashable) ?? 0)
        }

        return lhsSum < rhsSum
    }
}

