func move_one_ball(arr []int) bool {
    if len(arr) == 0 { // empty array, return True
        return true
    }

    min := arr[0]
    max := arr[len(arr)-1]

    for i := range arr {
        if arr[i] < min {
            min = arr[i]
        } else if arr[i] > max {
            max = arr[i]
        }
    }

    // Check if the first element is smaller than or equal to the last element
    return min <= max
}

func getMaxTriples(n: Int) -> Int {
    var count = 0
    for i in 1...n {
        let a_i = i * i - i + 1
        for j in (i + 1)...n {
            let a_j = j * j - j + 1
            for k in (j + 1)...n {
                let a_k = k * k - k + 1
                if (a_i + a_j + a_k) % 3 == 0 {
                    count += 1
                }
            }
        }
    }
    return count
}

