func max_fill(grid [][]int, capacity int) int {
	var totalWater int
	for _, row := range grid {
		for _, well := range row {
			if well == 1 {
				totalWater++
			}
		}
	}

	var bucketTrips int = totalWater / capacity
	var remainingWater int = totalWater % capacity

	if remainingWater > 0 {
		bucketTrips++
	}

	return bucketTrips
}

