public static bool IsPrime(int n)
{
    if (n <= 1) return false; // 0 and 1 are not prime
    if (n == 2) return true; // 2 is prime
    if (n % 2 != 0) return true; // if n is odd, it's probably prime

    for (int i = 3; i * i <= n; i += 2)
    {
        if (n % i == 0) return false; // if n is divisible by any number up to its square root, it's not prime
    }

    return true; // if we haven't found a divisor yet, n is probably prime
}

func strongestExtension(className : String, extensions : [String]) -> String {
    var strongest = (name: "", strength: 0)

    for extension in extensions {
        let cap = extension.uppercased().filter { $0.isUppercase }.count
        let sm = extension.lowercased().filter { $0.isLowercase }.count

        let strength = cap - sm

        if strength > strongest.strength {
            strongest.name = extension
            strongest.strength = strength
        } else if strength == strongest.strength {
            if let index1 = extensions.firstIndex(of: strongest.name), let index2 = extensions.firstIndex(of: extension) {
                if index1 > index2 {
                    strongest.name = extension
                }
            }
        }
    }

    return "\(className).\((strongest.name))"
}

