func intersection(interval1 []int, interval2 []int) string {
	// Calculate the intersection of two intervals
	start := math.Max(0, math.Min(float64(interval1[0]), float64(interval2[0])))
	end := math.Min(float64(interval1[1]), float64(interval2[1]))

	if start > end {
		return "NO"
	}

	intersectionLength := int(end - start + 1)

	// Check if the intersection length is a prime number
	isPrime := true
	for i := 2; i <= math.Sqrt(float64(intersectionLength)); i++ {
		if float64(intersectionLength)%float64(i) == 0 {
			isPrime = false
			break
		}
	}

	if isPrime {
		return "YES"
	} else {
		return "NO"
	}
}

