	fmt.Println(intersection([]int{1, 2}, []int{2, 3})) // prints NO
	fmt.Println(intersection([]int{-1, 1}, []int{0, 4}))   // prints NO
	fmt.Println(intersection([]int{-3, -1}, []int{-5, 5})) // prints YES
}

