    if (n <= 3) return when (n) { 0 -> 0; 1 -> 0; 2 -> 2; 3 -> 0 }

    val fib4Array = intArrayOf(0, 0, 2, 0)
    for (i in 4..n) {
        val sum = fib4Array[i - 1] + fib4Array[i - 2] + fib4Array[i - 3] + fib4Array[i - 4]
        fib4Array.set(i % 4, sum)
    }
    return fib4Array[n % 4]
}

