func simplify(x string, n string) bool {
	a, b := parseFraction(x)
	c, d := parseFraction(n)

	resultNumerator := a * c
	resultDenominator := b * d

	result := float64(resultNumerator) / float64(resultDenominator)

	if math.Mod(result, 1) == 0 {
		return true
	}

	return false
}

func parseFraction(frac string) (int, int) {
	parts := strings.Split(frac, "/")
	a, _ := strconv.Atoi(parts[0])
	b, _ := strconv.Atoi(parts[1])

	return a, b
}

func main() {
