func bf(planet1 string, planet2 string) []string {
	for i := 0; i < len(planets); i++ {
		if planets[i] == planet1 || planets[i] == planet2 {
			break
		}
	}

	if i >= len(planets) {
		return nil
	}

	j := -1
	for k := 0; k < len(planets); k++ {
		if planets[k] == planet2 {
			j = k
			break
		}
	}

	if j == -1 {
		return nil
	}

	var result []string
	for i++; i <= j; i++ {
		result = append(result, planets[i])
	}

	sort.Strings(result)
	return result
}

