def is_multiply_prime(a):
    def is_prime(n):
        if n < 2:
            return False
        for i in range(2, int(n**0.5) + 1):
            if n % i == 0:
                return False
        return True

    def multiply_primes():
        primes = []
        num = a
        while num > 1:
            for prime in primes:
                if num % prime == 0:
                    return [prime] * (num // prime)
            for i in range(2, int(num**0.5) + 1):
                if num % i == 0 and is_prime(i):
                    primes.append(i)
                    while num % i == 0:
                        num //= i
        if num > 1:
            return [num] * (a // num)
        return primes

    product = 1
    for prime in multiply_primes():
        product *= prime
    return product == a

