public class Main {
    public static int maxFill(int[][] grid, int capacity) {
        if (grid == null || grid.length == 0) return 0;

        int totalWater = 0; // total water in wells
        int bucketsNeeded = 0; // number of times to lower the bucket

        for (int[] row : grid) { // iterate over each well
            for (int unit : row) {
                if (unit == 1) { // add water from this well to total
                    totalWater += 1;
                }
            }
        }

        int bucketsUsed = 0; // number of buckets used

        while (totalWater > 0) { // until all water is gone
            int bucketSpace = capacity; // space left in current bucket

            for (int[] row : grid) {
                for (int unit : row) {
                    if (unit == 1 && bucketSpace > 0) { // fill up this well
                        totalWater -= 1;
                        bucketSpace--;
                    }
                }
            }

            bucketsUsed++; // increment number of buckets used

            while (bucketSpace < capacity) { // if not all space in bucket is used, empty it
                int waterInBucket = 0;

                for (int[] row : grid) {
                    for (int unit : row) {
                        if (unit == 1 && totalWater > 0) { // empty this well
                            totalWater -= 1;
                            waterInBucket++;
                        }
                    }
                }

                bucketSpace = capacity - waterInBucket; // update space left in current bucket
            }
        }

        return bucketsUsed;
    }

    public static void main(String[] args) {
        int[][] grid = {{0,0,1,0}, {0,1,0,0}, {1,1,1,1}};
        int capacity = 1;
        System.out.println(maxFill(grid, capacity)); // Output: 6
    }
}

