public class WillItFly {
    public static Boolean willItFly(List<Integer> q, int w) {
        // Check if the list is balanced (palindromic)
        String str = q.toString();
        boolean isBalanced = true;
        for(int i=0; i<str.length()/2; i++) {
            if(str.charAt(i) != str.charAt(str.length()-1-i)) {
                isBalanced = false;
                break;
            }
        }

        // Check if the sum of elements is less than or equal to the maximum possible weight
        int sum = 0;
        for(int num : q) {
            sum += num;
        }
        boolean isLightEnough = (sum <= w);

        return isBalanced && isLightEnough;
    }
}

