fun isMultiplyPrime(a: Int): Boolean {
    // Check if number 'a' can be factored into three prime numbers
    for (i in 2..100) { // Only need to check up to the square root of 'a'
        var p = i
        while (p * p <= a) {
            if (a % p == 0) {
                // Found a factor 'p'. Check if it is prime and if other two factors are also primes.
                if (!isPrime(p)) continue@continueFor
                for (j in p..100) { // Only need to check up to the square root of 'a'
                    var q = j
                    while (q * q <= a / p) {
                        if ((a / p) % q == 0) {
                            // Found other two factors 'q' and `a/p/q`. Check if they are prime.
                            if (!isPrime(p) || !isPrime(q)) continue@continueFor
                            return true
                        }
                        q++
                    }
                }
            }
            p++
        }
    }
    return false
}

