public static List<Integer> makeAPile(int n) {
    List<Integer> pile = new ArrayList<>();
    int currentLevel = 1;
    while (n > 0) {
        if ((currentLevel & 1) == 1) { // odd level
            pile.add(n);
            n -= n;
        } else { // even level
            pile.add(n);
            n = 0;
        }
        currentLevel++;
    }
    return pile;
}

