def largestPrimeFactor(n: Int): Int = {
  var maxFactor = 1
  var i = 2

  while (i * i <= n) {
    if (n % i == 0) {
      var j = i
      var factor = i
      while (n % j == 0) {
        factor = j
        j *= i
      }
      maxFactor = factor
      n /= factor
    } else {
      i += 1
    }
  }

  if (n > 1) {
    maxFactor = n
  }

  maxFactor
}

