public static int chooseNum(int x, int y) {
    // Check if both numbers are even
    if ((x % 2 == 0) && (y % 2 == 0)) {
        return Math.max(x, y);
    }

    // Check if only one number is even
    else if ((x % 2 == 0) || (y % 2 == 0)) {
        int maxEven = Math.max(x, y);
        if (maxEven % 2 == 0) {
            return maxEven;
        } else {
            for (int i = x; i <= y; i++) {
                if (i % 2 == 0) {
                    return i;
                }
            }
            return -1; // No even number found
        }
    }

    // Both numbers are odd
    else {
        for (int i = Math.max(x, y); i >= Math.min(x, y); i--) {
            if (i % 2 == 0) {
                return i;
            }
        }
        return -1; // No even number found
    }
}

