public static int LargestPrimeFactor(int n)
{
    int largestPF = 1; // Initialize the largest prime factor to 1

    for (int i = 2; i <= Math.Sqrt(n); i++)
    {
        while (n % i == 0) // While i is a factor of n
        {
            n /= i;
            largestPF = i; // Update the largest prime factor
        }
    }

    if (n > 1) // If n is still greater than 1, it means n itself is a prime number
    {
        largestPF = n;
    }

    return largestPF;
}

