    double sum = 0.0;
    for (int i = n; i <= m; i++) {
        sum += i;
    }

    double avg = Math.round(sum / (m - n + 1));
    String binary = Integer.toBinaryString((int) Math.round(avg));

    return "0b" + binary;
}

