public class MoveOneBall {
    public static boolean moveOneBall(List<Integer> arr) {
        if (arr.size() == 0) {
            return true;
        }

        int minIndex = 0;

        for (int i = 1; i < arr.size(); i++) {
            if (arr.get(i) < arr.get(minIndex)) {
                minIndex = i;
            }
        }

        // Check if the minimum value is at the start or not
        return minIndex == 0 || moveOneBall(Arrays.copyOfRange(arr, 1, arr.size()));
    }

    public static void main(String[] args) {
        List<Integer> arr = Arrays.asList(3, 4, 5, 1, 2);
        System.out.println(moveOneBall(arr)); // prints: true

        arr = Arrays.asList(3, 5, 4, 1, 2);
