class Exchange {
    /**
     * In this problem, you will implement a function that takes two lists of numbers,
     * and determines whether it is possible to perform an exchange of elements
     * between them to make lst1 a list of only even numbers.
     * There is no limit on the number of exchanged elements between lst1 and lst2.
     * If it is possible to exchange elements between the lst1 and lst2 to make
     * all the elements of lst1 to be even, return "YES".
     * Otherwise, return "NO".
     * For example:
     * exchange([1, 2, 3, 4], [1, 2, 3, 4]) => "YES"
     * exchange([1, 2, 3, 4], [1, 5, 3, 4]) => "NO"
     * It is assumed that the input lists will be non-empty.
     *
     */
    public static String exchange(List<Integer> lst1, List<Integer> lst2) {
        int oddCount = 0;

        // Count the number of odd numbers in lst1
        for (int num : lst1) {
            if (num % 2 != 0) {
                oddCount++;
            }
        }

        // If there are no odd numbers, it's possible to make all elements even
        if (oddCount == 0) {
            return "YES";
        } else {
            // If there are odd numbers in lst1 and they don't exist in lst2, it's impossible to make all elements even
            boolean foundOdd = false;
            for (int num : lst2) {
                if (num % 2 != 0) {
                    foundOdd = true;
                    break;
                }
            }

            // If there are odd numbers in both lists or no odd numbers exist in lst2, it's possible to make all elements even
            return !foundOdd ? "YES" : "NO";
        }
    }

    public static void main(String[] args) {
        List<Integer> lst1 = Arrays.asList(1, 2, 3, 4);
        List<Integer> lst2 = Arrays.asList(1, 5, 3, 4);

        System.out.println(exchange(lst1, lst2));
    }
}

