public class MaxFill {
    public static int maxFill(List<List<Integer>> grid, int capacity) {
        int totalWater = 0;
        int bucketCount = 0;

        for (List<Integer> row : grid) {
            for (int water : row) {
                totalWater += water;
            }

            while (totalWater > capacity) {
                totalWater -= capacity;
                bucketCount++;
            }
        }

        return bucketCount;
    }
}

