def isMultiplyPrime(a: Int): Boolean = {
  val primeNumbers = for {
    p <- (2 to a / 2).filter(isPrime)
  } yield p

  def isPrime(n: Int): Boolean = {
    if (n <= 1) false
    else !(2 until math.sqrt(n).toInt).exists(i => n % i == 0)
  }

  val primeProducts = for {
    p1 <- primeNumbers
    p2 <- primeNumbers.filter(_ != p1)
    p3 <- primeNumbers.filter(_ != p1 && _ != p2)
  } yield p1 * p2 * p3

  primeProducts.exists(_ == a)
}

