public class LargestSmallestIntegers {
    public static List<Integer> largestSmallestIntegers(List<Object> lst) {
        List<Integer> result = new ArrayList<>();

        // Initialize result with None values
        int maxNegative = Integer.MIN_VALUE;
        int minPositive = Integer.MAX_VALUE;

        for (Object obj : lst) {
            if (obj instanceof Integer) {
                int num = (int) obj;

                // Check if the number is negative
                if (num < 0) {
                    maxNegative = Math.max(maxNegative, num);
                } 
                // Check if the number is positive
                else if (num > 0) {
                    minPositive = Math.min(minPositive, num);
                }
            }
        }

        if (maxNegative == Integer.MIN_VALUE && minPositive == Integer.MAX_VALUE) {
            result.add(null);
            result.add(null);
        } 
        else if (maxNegative == Integer.MIN_VALUE) {
            result.add(null);
            result.add(minPositive);
        } 
        else if (minPositive == Integer.MAX_VALUE) {
            result.add(maxNegative);
            result.add(null);
        } 
        else {
            result.add(maxNegative);
            result.add(minPositive);
        }

        return result;
    }
}

public static bool IsMultiplyPrime(int a)
{
    // Function to check if a number is prime
    bool IsPrime(int n)
    {
        if (n <= 1) return false;
        for (int i = 2; i * i <= n; i++)
            if (n % i == 0) return false;
        return true;
    }

    // Function to find the prime factors of a number
    List<int> GetPrimeFactors(int n)
    {
        List<int> result = new List<int>();
        for (int i = 2; i <= n; i++)
            if (n % i == 0 && IsPrime(i))
                while (n % i == 0) { n /= i; result.Add(i); }
        if (n > 1) result.Add(n);
        return result;
    }

    // Main function
    List<int> factors = GetPrimeFactors(a).OrderBy(x => x).ToList();
    for (int i = 0; i < factors.Count - 2; i++)
    {
        int product = 1;
        for (int j = i; j <= i + 2; j++)
            product *= factors[j];
        if (product == a) return true;
    }
    return false;
}

