def isHappy(s: String): Boolean = {
  val len = s.length
  if (len < 3) false // string too short, not happy
  else {
    var prev = s.charAt(0)
    var curr = s.charAt(1)
    for (i <- 2 until len) {
      val next = s.charAt(i)
      if (prev == curr || curr == next) return false // consecutive letters are the same, not happy
      prev = curr
      curr = next
    }
    true // all 3-consecutive-letters are distinct, string is happy!
  }
}

fun exchange(lst1: List<Int>, lst2: List<Int>): String {
    val evenCount = lst1.count { it % 2 == 0 }
    if (evenCount == lst1.size) return "YES" // all elements in lst1 are even, no need to exchange

    val oddCount = lst1.size - evenCount
    val hasEnoughOddsInLst2 = lst2.count { it % 2 != 0 } >= oddCount
    if (!hasEnoughOddsInLst2) return "NO" // not enough odd elements in lst2 to make all of lst1 even

    return "YES" // we can exchange elements to make all of lst1 even
}

