class OrderByPoints {
    public static List<Object> orderByPoints(List<Object> nums) {
        if (nums == null || nums.size() == 0) {
            return new ArrayList<>();
        }

        // Convert the list to a custom class for easier sorting
        class NumWithSumAndIndex {
            int num;
            int sumOfDigits;
            int index;

            public NumWithSumAndIndex(int num, int index) {
                this.num = num;
                this.index = index;
                this.sumOfDigits = getSumOfDigits(num);
            }

            private int getSumOfDigits(int num) {
                int sum = 0;
                while (num > 0) {
                    sum += num % 10;
                    num /= 10;
                }
                return sum;
            }
        }

        List<NumWithSumAndIndex> listWithSumAndIndex = new ArrayList<>();
        for (int i = 0; i < nums.size(); i++) {
            listWithSumAndIndex.add(new NumWithSumAndIndex((Integer)nums.get(i), i));
        }

        Collections.sort(listWithSumAndIndex, new Comparator<NumWithSumAndIndex>() {
            public int compare(NumWithSumAndIndex a, NumWithSumAndIndex b) {
                if (a.sumOfDigits < b.sumOfDigits) return -1;
                else if (a.sumOfDigits > b.sumOfDigits) return 1;
                else return Integer.compare(a.index, b.index);
            }
        });

        List<Object> result = new ArrayList<>();
        for (NumWithSumAndIndex num : listWithSumAndIndex) {
            result.add(num.num);
        }

        return result;
    }
}

