fun reverseDelete(s: String, c: String): List<Any> {
    val sc = s.toCharArray()
    val cc = c.toCharArray()

    var left = 0
    var right = sc.size - 1

    while (left <= right) {
        while (left <= right && !cc.contains(sc[left].toChar())) {
            left++
        }

        while (left <= right && !cc.contains(sc[right].toChar())) {
            right--
        }

        if (left <= right) {
            sc[left] = ' '
            sc[right] = ' '
            c.toInt()
        }
    }

    val filteredString = sc.filterNot { it == ' ' }.joinToString("")

    return listOf(filteredString, filteredString.reversed() == filteredString)
}

