fun maxFill(grid: List<List<Int>>, capacity: Int): Int {
    var count = 0
    while (true) {
        var remainingWater = 0
        for (well in grid) {
            var waterInWell = 0
            for (unit in well) {
                if (unit == 1) {
                    waterInWell++
                }
            }
            remainingWater += Math.min(waterInWell, capacity)
        }
        if (remainingWater == 0) break
        count++
    }
    return count
}

