public class StrongestExtension {

    public static String strongestExtension(String className, List<String> extensions) {
        int strongest = Integer.MIN_VALUE;
        String strongestExt = "";

        for (String extension : extensions) {
            int cap = 0, sm = 0;

            for (char c : extension.toCharArray()) {
                if (Character.isUpperCase(c)) {
                    cap++;
                } else {
                    sm++;
                }
            }

            int strength = cap - sm;
            if (strength > strongest) {
                strongest = strength;
                strongestExt = extension;
            } else if (strength == strongest) {
                strongestExt = extension;
            }
        }

        return className + "." + strongestExt;
    }

    public static void main(String[] args) {
        List<String> extensions = new ArrayList<>();
        extensions.add("SErviNGSliCes");
        extensions.add("Cheese");
        extensions.add("StuFfed");

        System.out.println(strongestExtension("Slices", extensions)); // prints: Slices.SErviNGSliCes
    }
}

