fun intersection(interval1: List<Int>, interval2: List<Int>): String {
    val start = maxOf(interval1[0], interval2[0])
    val end = minOf(interval1[1], interval2[1])

    if (start > end) return "NO"

    val length = end - start + 1
    val isPrime = false

    if (length <= 1) {
        return "NO"
    }

    for (i in 2 until Math.sqrt(length.toDouble()).toInt() + 1) {
        if (length % i == 0) {
            isPrime = true
            break
        }
    }

    return if (isPrime) "YES" else "NO"
}

