fun tri(n: Int): List<Int> {
    if (n == 0) return listOf(3)
    if (n == 1) return listOf(1, 3)
    if (n == 2) return listOf(1, 3, 2)

    val result = mutableListOf<Int>(1, 3, 2)
    var evenTri = 2
    var oddTri = 8

    for (i in 3..n) {
        when (i % 2) {
            0 -> {
                result.add(evenTri)
                evenTri = 1 + i / 2
            }
            else -> {
                result.add(oddTri)
                val temp = oddTri
                oddTri = evenTri + oddTri + evenTri
                evenTri = temp
            }
        }
    }

    return result
}

const search = function (lst: Array<number>): number {
  const freqMap: { [key: number]: number } = {};

  // Create a frequency map for each integer in the list
  lst.forEach((num) => {
    if (!freqMap[num]) {
      freqMap[num] = 0;
    }
    freqMap[num]++;
  });

  // Find the greatest integer that has a frequency greater than or equal to its value
  let result: number | -1 = -1;
  for (const num in freqMap) {
    if (+num > 0 && freqMap[num] >= +num) {
      result = Math.max(result, +num);
    }
  }

  return result;
};

