const will_it_fly = function(q: Array<number>, w: number): boolean {
  // Check if the array is balanced (palindromic)
  const reversed = q.slice().reverse();
  if (!Array.prototype.every.call(q, (a, i) => a === reversed[i])) {
    return false; // not balanced
  }

  // Calculate the sum of elements
  const totalWeight = q.reduce((acc, current) => acc + current, 0);

  // Check if the sum is less than or equal to the maximum possible weight w
  return totalWeight <= w;
};

