const is_multiply_prime = (a: number): boolean => {
    const getPrimeFactors = (n: number): number[] => {
        let i = 2;
        const factors: number[] = [];
        while (i * i <= n) {
            if (n % i) {
                i++;
            } else {
                n /= i;
                factors.push(i);
                i = 2;
            }
        }
        if (n > 1) {
            factors.push(n);
        }
        return factors;
    };

    const primeFactors = getPrimeFactors(a);
    let foundThreePrimes = false;

    for (let i = 0; i < primeFactors.length - 2; i++) {
        for (let j = i + 1; j < primeFactors.length - 1; j++) {
            if (primeFactors[i] * primeFactors[j] === a) {
                foundThreePrimes = true;
                break;
            }
        }
        if (foundThreePrimes) {
            break;
        }
    }

    return foundThreePrimes;
};

