fun simplify(x: String, n: String): Boolean {
    val (a, b) = x.split("/").map { it.toInt() }
    val (c, d) = n.split("/").map { it.toInt() }

    val denominator = b * d

    if (denominator == 0) return false // Check for zero denominator

    val numerator = a * c
    val newNumerator = numerator / gcd(denominator)
    val newDenominator = denominator / gcd(denominator)

