public static List<int> MakeAPile(int n)
{
    List<int> pile = new List<int>();
    int count = n;

    while (count > 0)
    {
        if (n % 2 == 1) // if n is odd
        {
            pile.Add(2 * count + 1);
            count--;
        }
        else // if n is even
        {
            pile.Add(2 * count);
            count -= 2;
        }

        n--; // decrement n for the next level
    }

    return pile;
}

