public static int ChooseNum(int x, int y)
{
    // Check if both numbers are even
    if ((x % 2 == 0) && (y % 2 == 0))
    {
        return Math.Max(x, y);
    }
    else if ((x % 2 != 0) && (y % 2 == 0)) // x is odd, y is even
    {
        return y;
    }
    else if ((x % 2 == 0) && (y % 2 != 0)) // x is even, y is odd
    {
        return x;
    }
    else // both numbers are odd
    {
        int maxEven = Math.Max(x, y);
        for (int i = maxEven - 1; i > 0; i--)
        {
            if (i % 2 == 0)
            {
                return i;
            }
        }
        return -1; // no even number found
    }
}

