fun cycpatternCheck(a: String, b: String): Boolean {
    val lenA = a.length
    val lenB = b.length

    if (lenB > lenA) return false

    for (i in 0 until lenA - lenB + 1) {
        var j = 0
        while (j < lenB) {
            if (a[i + j] != b[j]) break
            j++
        }
        if (j == lenB) return true
    }

    for (i in 0 until lenA % lenB) {
        a += a.substring(0, lenA % lenB)
        for (j in 0 until lenB) {
            if (a[i + j] != b[j]) break
            j++
        }
        if (j == lenB) return true
    }

    return false
}

