public static string Exchange(List<int> lst1, List<int> lst2)
{
    foreach (int num in lst1)
    {
        if (num % 2 != 0) // if the number is odd
        {
            bool found = false;
            foreach (int num2 in lst2)
            {
                if (num2 % 2 == 0 && !found) // if the number is even and we haven't found a swap yet
                {
                    int index1 = lst1.IndexOf(num);
                    int index2 = lst2.IndexOf(num2);
                    lst1[index1] = num2;
                    lst2[index2] = num;
                    found = true;
                }
            }
            if (!found) // if we haven't found a swap, it's not possible to make all elements in lst1 even
            {
                return "NO";
            }
        }
    }
    return "YES";
}

