def maxFill(grid: List[List[Int]], capacity: Int): Int = {
  var numPours = 0
  while (grid.exists(well => well.sum > 0)) { // as long as there's still water in any well
    for ((well, i) <- grid.zipWithIndex) {
      val remainingWater = well.sum % capacity
      if (remainingWater > 0) { // if there's excess water left over after filling buckets
        numPours += 1 // increment the number of pours needed
      }
      well.foreach(_ -= capacity) // empty the well, minus any excess water
    }
  }
  numPours
}

public static int MaxFill(List<List<int>> grid, int capacity) 
{
    int maxFill = 0;

    foreach (List<int> row in grid)
    {
        int fill = 0;
        foreach (int cell in row)
        {
            if (cell == 1)
            {
                fill++;
            }
        }

        int fillsNeeded = fill / capacity + (fill % capacity > 0 ? 1 : 0);
        maxFill += fillsNeeded;
    }

    return maxFill;
}

