{
    int start = Math.Max(interval1[0], interval2[0]);
    int end = Math.Min(interval1[1], interval2[1]);

    if (start > end) return "NO";

    int length = end - start + 1;

    for (int i = 2; i * i <= length; i++)
    {
        while (length % i == 0)
        {
            length /= i;
        }
    }

    return length == 1 ? "YES" : "NO";
