    {
        public static List<object> Tri(int n)
        {
            List<object> tribonacciSequence = new List<object>();
            tribonacciSequence.Add(3);

            if (n == 0)
                return tribonacciSequence;

            for (int i = 1; i < n; i++)
            {
                if ((i & 1) == 0) // i is even
                    tribonacciSequence.Add(i * 2 + 1);
                else // i is odd
                    tribonacciSequence.Add((int)(tribonacciSequence[i - 1] + tribonacciSequence[i - 2] + tribonacciSequence[i - 3]));
            }
            return tribonacciSequence;
        }

