const exchange = function (lst1: number[], lst2: number[]) : string {
    let oddCount = 0;

    // Count the number of odd numbers in lst1
    for (let num of lst1) {
        if (num % 2 !== 0) {
            oddCount++;
        }
    }

    // If there are no odd numbers, it's possible to make all elements even by exchanging elements with lst2.
    if (oddCount === 0) return "YES";

    // If the number of odd numbers in lst1 is greater than or equal to the number of even numbers in lst2,
    // then it's not possible to make all elements of lst1 even by exchanging elements with lst2.
    for (let num of lst2) {
        if (num % 2 === 0 && oddCount > 0) {
            oddCount--;
        }
    }

    // If there are still odd numbers left in lst1, then it's not possible to make all elements of lst1 even by exchanging elements with lst2.
    if (oddCount > 0) return "NO";

    // Otherwise, it is possible to make all elements of lst1 even by exchanging elements with lst2.
    return "YES";
};

