    List<int> a = new List<int>();
    for (int i = 1; i <= n; i++)
    {
        a.Add((i * i - i + 1));
    }

    int count = 0;
    for (int i = 0; i < a.Count; i++)
    {
        for (int j = i + 1; j < a.Count; j++)
        {
            for (int k = j + 1; k < a.Count; k++)
            {
                if ((a[i] + a[j] + a[k]) % 3 == 0)
                {
                    count++;
                }
            }
        }
    }

    return count;
}

