using System;
using System.Collections.Generic;

namespace Solution
{
    public class Program
    {
        private static List<string> planets = new List<string>
        {
            "Mercury",
            "Venus",
            "Earth",
            "Mars",
            "Jupiter",
            "Saturn",
            "Uranus",
            "Neptune"
        };

        /// <summary>
        /// This function takes two planet names as strings and returns a tuple containing 
        /// all planets whose orbits are located between the orbit of planet1 and the orbit 
        /// of planet2, sorted by the proximity to the sun. If planet1 or planet2 are not 
        /// correct planet names, it returns an empty list.
        /// </summary>
        public static List<string> Bf(string planet1, string planet2)
        {
            int index1 = planets.IndexOf(planet1);
            int index2 = planets.IndexOf(planet2);

            if (index1 == -1 || index2 == -1)
                return new List<string>();

            int start = Math.Min(index1, index2);
            int end = Math.Max(index1, index2);

            List<string> result = new List<string>();
            for (int i = 0; i < planets.Count; i++)
            {
                if (i >= start && i <= end)
                    continue;
                if (i < start || i > end)
                    result.Add(planets[i]);
            }

            return result;
        }
    }
}

def xOrY(n: Int, x: Int, y: Int): Int = {
  def isPrime(m: Int): Boolean = {
    if (m <= 1) false
    else {
      var i = 2
      while (i * i <= m) {
        if (m % i == 0) return false
        i += 1
      }
      true
    }
  }

  if (isPrime(n)) x else y
}

const intersection = function (interval1: [number, number], interval2: [number, number]) : string {
  // Calculate the start and end of the intersection
  let start = Math.max(interval1[0], interval2[0]);
  let end = Math.min(interval1[1], interval2[1]);

  // Check if the intervals intersect
  if (start > end) return "NO";

  // Calculate the length of the intersection
  let length = end - start + 1;

  // Check if the length is a prime number
  function isPrime(n: number): boolean {
    if (n <= 1) return false;
    for (let i = 2; i * i <= n; i++) {
      if (n % i === 0) return false;
    }
    return true;
  }

  // Return the result
  return isPrime(length) ? "YES" : "NO";
};

