const tri = function(n: number): Array<number> {
  if (n === 0) return [3]; // base case for n=0
  if (n === 1) return [1, 3]; // base case for n=1

  const tribonacciSequence: Array<number> = [1, 3];
  for (let i = 2; i <= n; i++) {
    let nextTri: number;
    if (i % 2 === 0) { // even index
      nextTri = 1 + i / 2;
    } else { // odd index
      const prevTwoTri: number[] = tribonacciSequence.slice(-2);
      nextTri = prevTwoTri[0] + prevTwoTri[1] + (tribonacciSequence[tribonacciSequence.length - 3] ?? 0);
    }
    tribonacciSequence.push(nextTri);
  }
  return tribonacciSequence;
};

public static int DoubleTheDifference(List<object> lst)
{
    return lst.Where(x => x is int && (int)x > 0).Select(x => (int)x * (int)x).Sum();
}

def strongestExtension(className: String, extensions: List[String]): String = {
  val maxStrength = extensions.map(extension => {
    val capCount = extension.count(c => c.isUpper)
    val smCount = extension.length - capCount
    (capCount - smCount).toDouble / extension.length
  }).max

  val strongestExtensions = extensions.filter(extension => {
    val capCount = extension.count(c => c.isUpper)
    val smCount = extension.length - capCount
    (capCount - smCount) == maxStrength
  })

  strongestExtensions.headOption.getOrElse(extensions.head) + "." + className
}

const digits = (n: number): number => {
  let product = 1;
  while (n > 0) {
    const digit = n % 10;
    if (digit % 2 !== 0) { // check if digit is odd
      product *= digit;
    }
    n = Math.floor(n / 10);
  }
  return product;
};

public static string StrongestExtension(string className, List<string> extensions)
{
    if (extensions == null || extensions.Count == 0)
    {
        return className;
    }

    var strongestExtension = extensions.First();
    var strongestStrength = GetStrength(strongestExtension);

    foreach (var extension in extensions)
    {
        var strength = GetStrength(extension);
        if (strength > strongestStrength)
        {
            strongestExtension = extension;
            strongestStrength = strength;
        }
        else if (strength == strongestStrength)
        {
            if (extensions.IndexOf(extension) < extensions.IndexOf(strongestExtension))
            {
                strongestExtension = extension;
            }
        }
    }

    return className + "." + strongestExtension;
}

private static int GetStrength(string extension)
{
    var cap = 0;
    var sm = 0;

    foreach (var c in extension)
    {
        if (char.IsUpper(c))
        {
            cap++;
        }
        else
        {
            sm++;
        }
    }

    return cap - sm;
}

