    val lenB = b.length
    for (i <- 0 until a.length) {
      if (a.substring(i).startsWith(b)) return true
      if (lenB > 1 && i + lenB <= a.length) {
        if (a.substring(i, i+lenB).equals(b) || a.substring(i).startsWith(b)) return true
      }
    }
    false
  }

  println(cycpatternCheck("abcd", "abd")) // => False
  println(cycpatternCheck("hello", "ell")) // => True
  println(cycpatternCheck("whassup", "psus")) // => False
  println(cycpatternCheck("abab", "baa")) // => True
  println(cycpatternCheck("efef", "eeff")) // => False
  println(cycpatternCheck("himenss", "simen")) // => True
}

public static bool CycpatternCheck(string a, string b)
{
    if (b.Length > a.Length)
        return false;

    for (int i = 0; i < a.Length; i++)
    {
        for (int j = 0; j <= a.Length - b.Length; j++)
        {
            if (a.Substring(j, b.Length).Equals(b))
                return true;
            else if (a.Substring(i) + a.Substring(0, i).Substring(a.Length - i) == b)
                return true;
        }
    }

    return false;
}

const is_nested = function (string0: string): boolean {
  let depth = 0;
  for (let char of string0) {
    if (char === '[') {
      depth++;
    } else if (char === ']') {
      if (depth > 0) {
        depth--;
      } else {
        return false; // mismatched closing bracket
      }
    }
  }
  return depth > 0; // at least one nested bracket
};

def intToMiniRoman(number: Int): String = {
  val romanMap = Map(
    1000 -> "m",
    900 -> "cm",
    500 -> "d",
    400 -> "cd",
    100 -> "c",
    90 -> "xc",
    50 -> "l",
    40 -> "xl",
    10 -> "x",
    9 -> "ix",
    5 -> "v",
    4 -> "iv",
    1 -> "i"
  )

  def toRoman(n: Int): String = {
    var result = ""
    for ((roman, arabic) <- romanMap.toList) {
      val count = n / arabic
      result += (count * roman)
      n %= arabic
    }
    result
  }

  if (number < 1 || number > 1000) {
    throw new AssertionError("Number must be between 1 and 1000")
  }

  toRoman(number).toLowerCase
}

public static string IntToMiniRoman(int number)
{
    if (number < 1 || number > 1000)
    {
        throw new ArgumentOutOfRangeException("Number must be between 1 and 1000");
    }

    Dictionary<int, string> romanNumerals = new Dictionary<int, string>
    {
        {1000,"m"},
        {900,"cm"},
        {500,"d"},
        {400,"cd"},
        {100,"c"},
        {90,"cx"},
        {50,"l"},
        {40,"xl"},
        {10,"x"},
        {9,"ix"},
        {5,"v"},
        {4,"iv"},
        {1,"i"}
    };

    string result = "";

    foreach (var pair in romanNumerals.OrderByDescending(x => x.Key))
    {
        while (number >= pair.Key)
        {
            number -= pair.Key;
            result += pair.Value;
        }
    }

    return result.ToLower();
}

def rightAngleTriangle(a: Int, b: Int, c: Int): Boolean = {
  val sides = List(a, b, c)
  sides.sort(By( (_, _) => _ )) match {
    case List(x, y, z) =>
      (x * x + y * y == z * z) || (x * x + z * z == y * y) || (y * y + z * z == x * x)
  }
}

