public static bool RightAngleTriangle(int a, int b, int c)
{
    // A right-angled triangle must have one side that is the hypotenuse of a Pythagorean triple.
    // We can use this to determine if the sides form a right-angled triangle.
    return (a * a + b * b == c * c) || (a * a + c * c == b * b) || (b * b + c * c == a * a);
}

