const checkIfLastCharIsALetter = function(txt: string): boolean {
    const lastChar = txt.charAt(txt.length - 1);
    const isLetter = /^[a-zA-Z]+$/.test(lastChar); // Check if the last character is an alphabetical character
    const isPartOfWord = /^[a-zA-Z\s]+$/i.test(txt.slice(0, txt.length - 1)); // Check if the last character is part of a word

