    let maxNegative = null;
    let minPositive = null;

    for (let num of lst) {
        if (num < 0 && (!maxNegative || num > maxNegative)) {
            maxNegative = num;
        } else if (num > 0 && (!minPositive || num < minPositive)) {
            minPositive = num;
        }
    }

    return [maxNegative, minPositive];
};

using System;
