namespace Solution
{
    public class Program
    {
        /// <summary> 
        /// You're an expert C# programmer
        /// 
        /// Given two positive integers a and b, return the even digits between a
        /// and b, in ascending order.
        /// 
        /// For example:
        /// GenerateIntegers(2, 8) => [2, 4, 6, 8]
        /// GenerateIntegers(8, 2) => [2, 4, 6, 8]
        /// GenerateIntegers(10, 14) => []
        /// 
        /// </summary>
        public static List<int> GenerateIntegers (int a, int b) 
        {
            List<int> result = new List<int>();

            for(int i = Math.Min(a, b); i <= Math.Max(a, b); i++)
            {
                if(i.ToString().Select(c => int.Parse(c.ToString())).All(c => c % 2 == 0))
                {
                    result.Add(i);
                }
            }

            return result.OrderBy(x => x).ToList();
        }

        public static void Main(string[] args)
        {
            List<int> integers = GenerateIntegers(8, 2);
            foreach (int integer in integers)
            {
                Console.WriteLine(integer);
            }
        }
    }
}

const special_factorial = function (n: number): number {
    if (n <= 0) {
        throw new Error('Input must be a positive integer');
    }

    let result = 1;
    for (let i = n; i >= 2; i--) {
        result *= factorial(i);
    }
    return result;
};

const factorial = function (n: number): number {
    if (n <= 0) {
        return 1;
    } else {
        return n * factorial(n - 1);
    }
};

