const simplify = (x: string, n: string): boolean => {
  const [xNumerator, xDenominator] = x.split('/').map(Number);
  const [nNumerator, nDenominator] = n.split('/').map(Number);

  // Calculate the product of the two fractions
  const numerator = xNumerator * nNumerator;
  const denominator = xDenominator * nDenominator;

  // Check if the product is a whole number (i.e., the numerator is equal to the denominator)
  return numerator === denominator;
};

const order_by_points = function(nums: number[]): number[] {
    return nums.sort((a, b) => {
        const sumA = a.toString().split('').reduce((acc, curr) => parseInt(curr, 10) + acc, 0);
        const sumB = b.toString().split('').reduce((acc, curr) => parseInt(curr, 10) + acc, 0);

        if (sumA === sumB) {
            return nums.indexOf(a) - nums.indexOf(b);
        } else {
            return sumA - sumB;
        }
    });
};

