const double_the_difference = function (lst: Array<number>): number {
    let sumOfSquares = 0;

    // Filter the list to include only positive integers that are odd
    const oddNumbers = lst.filter(n => n > 0 && typeof n === 'number' && n % 2 !== 0);

    // Calculate the sum of squares for these numbers
    for (const number of oddNumbers) {
        sumOfSquares += Math.pow(number, 2);
    }

    return sumOfSquares;
};

const Strongest_Extension = function(class_name: string, extensions: Array<string>): string {
    let strongestExtension = '';
    let maxStrength = -Infinity;

    for (let i = 0; i < extensions.length; i++) {
        const extension = extensions[i];
        let cap = 0;
        let sm = 0;

        for (let j = 0; j < extension.length; j++) {
            if (extension[j] === extension[j].toUpperCase()) {
                cap++;
            } else if (extension[j] === extension[j].toLowerCase()) {
                sm++;
            }
        }

        const strength = cap - sm;
        if (strength > maxStrength) {
            strongestExtension = extension;
            maxStrength = strength;
        }
    }

    return class_name + '.' + strongestExtension;
};

