const right_angle_triangle = function (a: number, b: number, c: number): boolean {
  // Check if all three sides form a valid triangle
  if (a + b <= c || a + c <= b || b + c <= a) {
    return false; // Not a valid triangle
  }

  // Check if the square of one side is equal to the sum of squares of the other two sides
  const half = Math.sqrt(a * a + b * b);
  return half === c;
};

const solve = function(s: string): string {
  return s.split('').map(c => {
    if (!isNaN(Number(c))) {
      // If the character is a digit, reverse its order
      const digitIndex = parseInt(c);
      const reversedDigit = digitIndex.toString().split('').reverse().join('');
      return reversedDigit;
    } else if (/^[a-zA-Z]+$/.test(c)) {
      // If the character is a letter, reverse its case
      return c.toUpperCase();
    } else {
      // If the character is neither a digit nor a letter, keep it as is
      return c;
    }
  }).join('');
};

const string_to_md5 = function (text: string): string | null {
    if (!text) return null;

    const crypto = require('crypto');
    const md5 = crypto.createHash('md5');
    md5.update(text);
    return md5.digest('hex').toString();
};

